"use client";

import type { Variants } from "motion/react";
import { motion, useAnimation } from "motion/react";
import { forwardRef, useCallback, useImperativeHandle, useRef } from "react";
import { cn } from "@/lib/utils";

// 1. Handle interface (always startAnimation + stopAnimation)
export interface ArrowRightIconHandle {
  startAnimation: () => void;
  stopAnimation: () => void;
}

// 2. Props interface (HTMLAttributes<HTMLDivElement> + size)
interface ArrowRightIconProps extends React.HTMLAttributes<HTMLDivElement> {
  size?: number;
}

// 3. Variants with "animate" and "normal" states
const shaftVariants: Variants = {
  animate: { d: ["M5 12h14", "M5 12h9", "M5 12h14"], transition: { duration: 0.36 } },
  normal:  { d: "M5 12h14" },
};

// 4. forwardRef component with imperative handle
export const ArrowRightIcon = forwardRef<ArrowRightIconHandle, ArrowRightIconProps>(
  ({ className, onMouseEnter, onMouseLeave, size = 18, ...props }, ref) => {
    const controls = useAnimation();
    const controlledRef = useRef(false);

    useImperativeHandle(ref, () => {
      controlledRef.current = true;
      return {
        startAnimation: () => controls.start("animate"),
        stopAnimation:  () => controls.start("normal"),
      };
    });

    // 5. Auto-play on hover, respect controlled ref
    const handleMouseEnter = useCallback((event) => {
      if (controlledRef.current) { onMouseEnter?.(event); return; }
      void controls.start("animate");
    }, [controls, onMouseEnter]);

    const handleMouseLeave = useCallback((event) => {
      if (controlledRef.current) { onMouseLeave?.(event); return; }
      void controls.start("normal");
    }, [controls, onMouseLeave]);

    // 6. Wrapper div + SVG with motion.path
    return (
      <div className={cn(className)} onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseLeave} {...props}>
        <svg fill="none" height={size} stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24" width={size}>
          <motion.path animate={controls} d="M5 12h14" variants={shaftVariants} />
          <motion.path animate={controls} d="m12 5 7 7-7 7" variants={headVariants} />
        </svg>
      </div>
    );
  }
);
```

